class ParkingSystem {
public:
    ParkingSystem(int big, int medium, int small) : big(big), medium(medium), small(small) {}

    bool addCar(int carType) {
        if (carType == 1 && big > 0) {
            big--;
            return true;
        } else if (carType == 2 && medium > 0) {
            medium--;
            return true;
        } else if (carType == 3 && small > 0) {
            small--;
            return true;
        }
        return false;
    }
private:
    int big;
    int medium;
    int small;
};
